import React, { useState } from "react";
import {
  Box,
  Heading,
  VStack,
  FormControl,
  FormLabel,
  Input,
  Button,
  Avatar,
  Center,
  useToast,
  Container,
  Text
} from "@chakra-ui/react";
import axios from "axios";
import UserNavbar from "../components/UserComponents/UserNavbar"; 
import { useDispatch, useSelector } from "react-redux";
import { actionLoginSuccess } from "../Redux/UserReducer/actionType";
import { showToast } from "../components/SignUp";
import { useNavigate } from "react-router-dom";

const ProfilePage = () => {
  const userStore = useSelector((store) => store.UserReducer);

  const [name, setName] = useState(userStore?.name || "");
  const [email, setEmail] = useState(userStore?.email || "");
  const [password, setPassword] = useState("");
  const [age, setAge] = useState(userStore?.age || "");
  const [city, setCity] = useState(userStore?.place || "");
  const [job, setJob] = useState(
    (userStore?.job !== "null" && userStore?.job) || ""
  );

  const dispatch = useDispatch();
  const toast = useToast();
  const navigate = useNavigate();

  const handleSave = () => {
    const obj = { name, email, password, age, city, job };
    const id = userStore?.userId;

    axios
      .patch(
        `https://elearning-platform-using-mern-j5py.vercel.app/users/update/${id}`,
        obj
      )
      .then((res) => {
        dispatch(actionLoginSuccess(res?.data));
        localStorage.setItem(
          "user",
          JSON.stringify({
            email: res.data.user.email,
            name: res.data.user.name,
            role: res.data.user.role,
            token: res.data.token,
            isAuth: true,
            userId: res.data.user._id,
            age: res.data.user.age,
            job: res.data.user.job,
            place: res.data.user.city,
          })
        );
        navigate(-1);
        showToast({ toast, message: "Profile Updated", color: "green" });
      })
      .catch((err) => {
        showToast({ toast, message: "Error occur", color: "red" });
        console.log(err);
      });
  };

  return (
    <Box bg="#f7f9fa" minH="100vh">
      
      {/* Navbar */}
      <UserNavbar />

      {/* Content */}
      <Container maxW="container.md" pt="100px">
        <Box
          bg="#ffffff"
          border="1px solid #e5e7eb"
          borderRadius="12px"
          p={8}
          boxShadow="lg"
        >
          {/* Avatar */}
          <Center mb={6}>
            <Avatar size="2xl" name={name} />
          </Center>

          {/* Title */}
          <Heading mb={2} fontSize="2xl" textAlign="center" color="#1c1d1f">
            Edit Profile
          </Heading>
          <Text mb={6} textAlign="center" color="gray.500">
            Update your personal information
          </Text>

          {/* Form */}
          <VStack spacing={4} align="stretch">
            <FormControl isRequired>
              <FormLabel>Name</FormLabel>
              <Input value={name} onChange={(e) => setName(e.target.value)} />
            </FormControl>

            <FormControl isRequired>
              <FormLabel>Email</FormLabel>
              <Input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </FormControl>

            <FormControl>
              <FormLabel>Password</FormLabel>
              <Input
                type="password"
                placeholder="Leave blank if unchanged"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </FormControl>

            <FormControl isRequired>
              <FormLabel>Age</FormLabel>
              <Input
                type="number"
                value={age}
                onChange={(e) => setAge(e.target.value)}
              />
            </FormControl>

            <FormControl isRequired>
              <FormLabel>City</FormLabel>
              <Input value={city} onChange={(e) => setCity(e.target.value)} />
            </FormControl>

            <FormControl isRequired>
              <FormLabel>Job</FormLabel>
              <Input value={job} onChange={(e) => setJob(e.target.value)} />
            </FormControl>

            {/* Button */}
            <Button
              mt={4}
              bg="#A435F0"
              color="white"
              _hover={{ bg: "#8710d8" }}
              isDisabled={
                name === "" ||
                email === "" ||
                age === "" ||
                city === "" ||
                job === ""
              }
              onClick={handleSave}
            >
              Save Changes
            </Button>
          </VStack>
        </Box>
      </Container>
    </Box>
  );
};

export default ProfilePage;
